sql:
SELECT play_result
FROM plays
WHERE play_id = 0;

SELECT COUNT(*) 
FROM plays 
WHERE offense_team_id = (SELECT team_id FROM teams WHERE team_name = 'UT Martin');

SELECT COUNT(DISTINCT player_id) AS total_players
FROM play_stats
WHERE stat_type = 'offensive';

SELECT AVG(plays_count) AS average_plays_per_drive
FROM drive_stats
WHERE drive_type = 'Offensive';

SELECT COUNT(*)
FROM games
WHERE game_id = 0;

SELECT play_id, play_index, type 
FROM plays 
WHERE game_id = 1 AND quarter = 1 AND type = 'Kickoff';

SELECT game_id, penalties_count, penalties_yards
FROM game_stats
WHERE final_result = 'Win' AND penalties_count > 0;
